python -c "
from pathlib import Path
import os
root = Path(os.environ.get('CLAUDE_PROJECT_DIR', os.getcwd()))
plans_dir = root / 'docs' / 'plans'
reviews_dir = root / 'docs' / 'review'
pf = list(plans_dir.glob('*.md')) if plans_dir.exists() else []
rf = list(reviews_dir.glob('*.md')) if reviews_dir.exists() else []
pending = []
active = []
for plan in pf:
    sf = plan.with_suffix('.status')
    if sf.exists():
        s = sf.read_text().strip()
        if s == 'in-progress':
            active.append(plan.stem)
    else:
        pending.append(plan.stem)
print(f'[WORKFLOW] {len(pf)} plans ({len(pending)} pending, {len(active)} active) | {len(rf)} reviews')
if pending:
    for p in pending:
        print(f'  PENDING: docs/plans/{p}.md')
if active:
    for p in active:
        print(f'  ACTIVE: docs/plans/{p}.md')
" 2>&1 || true
